# Linker version script — export only the public C API.
# Paired with CMakeLists.txt via -Wl,--version-script=...
#
# Why a version script instead of C_VISIBILITY_PRESET=hidden + annotations:
# ipc_v1.{h,c} is auto-generated by wayproto-gen, so hand-annotating its
# prototypes with an export macro would be lost on regeneration. All
# non-static symbols in bridge.c / ipc_v1.c are prefixed ww_, so one
# glob keeps the exported surface in lockstep with the public headers.
WAYWALLEN_BRIDGE_0 {
    global:
        ww_*;
    local:
        *;
};
